import { Component, ElementRef, ViewChild, AfterViewInit, input, output, effect, OnDestroy, ViewEncapsulation } from '@angular/core';
import * as d3 from 'd3';
import { FamilyMember } from '../../data/mock-data';

@Component({
  selector: 'app-family-tree',
  standalone: true,
  template: `
    <div class="relative w-full h-full bg-white rounded-xl shadow-inner overflow-hidden border border-slate-200">
      <div #chartContainer class="w-full h-full cursor-move"></div>

      <div class="absolute top-4 right-4 bg-white/90 p-3 rounded-lg shadow-md border border-slate-200 text-xs text-slate-600 pointer-events-none z-10">
        <div class="flex items-center gap-2 mb-1">
          <span class="w-3 h-3 rounded-full bg-blue-100 border border-blue-500"></span>
          <span>זכר</span>
        </div>
        <div class="flex items-center gap-2 mb-1">
          <span class="w-3 h-3 rounded-full bg-pink-100 border border-pink-500"></span>
          <span>נקבה</span>
        </div>
        <div class="mt-2 font-bold">הוראות:</div>
        <ul class="list-disc list-inside">
          <li>לחץ על כרטיס לפרטים</li>
          <li>לחץ על העיגול הצבעוני להסתיר ילדים</li>
          <li>גרור כרטיסים לסידור מחדש</li>
          <li>גלול לזום, גרור רקע להזזה</li>
        </ul>
      </div>
    </div>
  `,
  styles: [`
    :host {
      display: block;
      width: 100%;
      height: 100%;
    }
  `],
  encapsulation: ViewEncapsulation.None
})
export class FamilyTreeComponent implements AfterViewInit, OnDestroy {
  rootData = input.required<FamilyMember>();
  memberSelected = output<FamilyMember>();

  @ViewChild('chartContainer') private containerRef!: ElementRef<HTMLDivElement>;

  private svg: any;
  private g: any;
  private root: any;
  private treeLayout: any;
  private width = 0;
  private height = 0;
  private duration = 500;
  private i = 0; // id counter for nodes

  constructor() {
    effect(() => {
      const data = this.rootData();
      if (this.svg && data) {
        this.initializeTree(data);
      }
    });
  }

  ngAfterViewInit() {
    setTimeout(() => {
      if (this.rootData()) {
        this.initializeTree(this.rootData());
      }
    }, 100);

    // Handle resize
    window.addEventListener('resize', this.handleResize);
  }

  ngOnDestroy() {
    window.removeEventListener('resize', this.handleResize);
  }

  private handleResize = () => {
    if (this.rootData()) {
      this.initializeTree(this.rootData());
    }
  }

  private initializeTree(data: FamilyMember) {
    if (!this.containerRef) return;

    // Clear previous
    d3.select(this.containerRef.nativeElement).selectAll('*').remove();

    this.width = this.containerRef.nativeElement.clientWidth;
    this.height = this.containerRef.nativeElement.clientHeight;

    // Create SVG
    this.svg = d3.select(this.containerRef.nativeElement)
      .append('svg')
      .attr('width', '100%')
      .attr('height', '100%')
      .attr('viewBox', `0 0 ${this.width} ${this.height}`)
      .call(d3.zoom().scaleExtent([0.1, 3]).on('zoom', (event) => {
        this.g.attr('transform', event.transform);
      }))
      .on('dblclick.zoom', null); // Disable double click zoom

    this.g = this.svg.append('g')
      .attr('transform', `translate(${this.width / 2}, 100)`);

    // Define tree layout
    this.treeLayout = d3.tree().nodeSize([220, 180]); // Width between siblings, height between generations

    // Convert data to hierarchy
    this.root = d3.hierarchy<FamilyMember>(data, (d) => d.children);

    // Initial position
    this.root.x0 = 0;
    this.root.y0 = 0;

    // Collapse after the second generation initially to show "expand" feature
    // Optional: Uncomment next line to collapse by default on load
    // if (this.root.children) this.root.children.forEach(collapse);

    this.update(this.root);
  }

  private update(source: any) {
    const treeData = this.treeLayout(this.root);
    const nodes = treeData.descendants();
    const links = treeData.links();

    // ------------------- NODES -------------------
    const node = this.g.selectAll('g.node')
      .data(nodes, (d: any) => d.id || (d.id = ++this.i));

    // Enter new nodes at the parent's previous position
    const nodeEnter = node.enter().append('g')
      .attr('class', 'node')
      .attr('transform', (d: any) => `translate(${source.x0},${source.y0})`)
      // Add Drag behavior
      .call(d3.drag()
        .on('start', function() { d3.select(this).raise(); }) // Bring to front
        .on('drag', (event, d: any) => {
           d.x = event.x;
           d.y = event.y;
           d3.select(this).attr('transform', `translate(${d.x},${d.y})`);
           this.updateLinks(); // Update lines dynamically while dragging
        })
        .on('end', () => {
           // Optional: could snap to grid or save position
        })
      );

    // Card dimensions
    const rectW = 180;
    const rectH = 90;
    const cornerRadius = 8;

    // --- Card Background ---
    nodeEnter.append('rect')
      .attr('width', rectW)
      .attr('height', rectH)
      .attr('x', -rectW / 2)
      .attr('y', -rectH / 2)
      .attr('rx', cornerRadius)
      .attr('ry', cornerRadius)
      .attr('class', (d: any) => {
        const genderClass = d.data.gender === 'male' 
          ? 'fill-blue-50 stroke-blue-200' 
          : 'fill-pink-50 stroke-pink-200';
        return `${genderClass} stroke-2 shadow-sm transition-colors hover:shadow-md`;
      })
      .on('click', (event: any, d: any) => {
        // Prevent bubble up to drag
        event.stopPropagation();
        this.memberSelected.emit(d.data);
      });

    // --- Name Text ---
    nodeEnter.append('text')
      .attr('dy', -15)
      .attr('text-anchor', 'middle')
      .text((d: any) => d.data.name)
      .attr('class', 'text-sm font-bold fill-slate-800 pointer-events-none');

    // --- Spouses Text ---
    nodeEnter.append('text')
      .attr('dy', 5)
      .attr('text-anchor', 'middle')
      .text((d: any) => {
        if (d.data.spouses && d.data.spouses.length > 0) {
          return '❤️ ' + d.data.spouses.map((s: any) => s.name).join(', ');
        }
        return '';
      })
      .attr('class', 'text-[10px] fill-slate-500 pointer-events-none')
      .each(function(this: SVGTextElement, d: any) {
        // Simple text wrapping or truncation could go here if needed
        // For now, relying on SVG overflow hidden nature if too long, 
        // or just letting it run (simple implementation)
      });

    // --- Generation Label (Optional) ---
    nodeEnter.append('text')
      .attr('dy', 25)
      .attr('text-anchor', 'middle')
      .text((d: any) => `דור ${d.depth + 1}`)
      .attr('class', 'text-[9px] fill-slate-400 uppercase tracking-widest pointer-events-none');

    // --- Toggle Button Circle (for expand/collapse) ---
    const circleGroup = nodeEnter.append('g')
        .attr('class', 'toggle-btn cursor-pointer')
        .attr('transform', `translate(0, ${rectH/2})`)
        .on('click', (event: any, d: any) => {
            event.stopPropagation(); // Stop click from triggering card select
            this.click(d);
        });

    circleGroup.append('circle')
      .attr('r', 8)
      .attr('class', (d: any) => d.data.gender === 'male' ? 'fill-blue-500 stroke-white' : 'fill-pink-500 stroke-white')
      .attr('stroke-width', 2);

    // +/- Icon
    circleGroup.append('text')
      .attr('dy', 3)
      .attr('text-anchor', 'middle')
      .attr('class', 'text-[10px] fill-white font-bold select-none')
      .text((d: any) => d._children ? '+' : (d.children ? '-' : ''));

    // UPDATE nodes
    const nodeUpdate = node.merge(nodeEnter);

    nodeUpdate.transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${d.x},${d.y})`);

    // Update toggle text
    nodeUpdate.select('.toggle-btn text')
       .text((d: any) => d._children ? '+' : (d.children ? '-' : ''));

    // Hide toggle button if no children
    nodeUpdate.select('.toggle-btn')
       .attr('display', (d: any) => (d.children || d._children) ? 'block' : 'none');

    // EXIT nodes
    const nodeExit = node.exit().transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${source.x},${source.y})`)
      .remove();

    nodeExit.select('rect').attr('r', 1e-6);
    nodeExit.select('text').style('fill-opacity', 1e-6);

    // ------------------- LINKS -------------------
    this.updateLinks(source, links);

    // Store positions for next animation
    nodes.forEach((d: any) => {
      d.x0 = d.x;
      d.y0 = d.y;
    });
  }

  private updateLinks(source?: any, linksData?: any) {
    // If not provided (dragging), re-calculate based on current nodes
    if (!linksData) {
        linksData = this.treeLayout(this.root).links();
    }

    // Function to generate path
    const diagonal = (s: any, d: any) => {
        // Vertical tree: x is horizontal position, y is depth
        return `M ${s.x} ${s.y + 45}
                C ${s.x} ${s.y + 45 + 50},
                  ${d.x} ${d.y - 45 - 50},
                  ${d.x} ${d.y - 45}`;
    };

    const link = this.g.selectAll('path.link')
      .data(linksData, (d: any) => d.target.id);

    // Enter
    const linkEnter = link.enter().insert('path', 'g')
      .attr('class', 'link')
      .attr('d', (d: any) => {
        const o = { x: source?.x0 || this.root.x0, y: source?.y0 || this.root.y0 };
        return diagonal(o, o); // Start from collapsed position
      });

    // Update (Merge)
    const linkUpdate = link.merge(linkEnter);

    if (source) {
       // If source is provided, we are animating (expand/collapse)
       linkUpdate.transition()
        .duration(this.duration)
        .attr('d', (d: any) => diagonal(d.source, d.target));
    } else {
       // If no source (dragging), update immediately without transition
       linkUpdate.attr('d', (d: any) => diagonal(d.source, d.target));
    }

    // Exit
    if (source) {
        link.exit().transition()
        .duration(this.duration)
        .attr('d', (d: any) => {
            const o = { x: source.x, y: source.y };
            return diagonal(o, o);
        })
        .remove();
    } else {
        link.exit().remove();
    }
  }

  // Toggle children on click
  private click(d: any) {
    if (d.children) {
      d._children = d.children;
      d.children = null;
    } else {
      d.children = d._children;
      d._children = null;
    }
    this.update(d);
  }
}

import { Component, signal } from '@angular/core';
import { CommonModule, DatePipe } from '@angular/common';
import { FamilyTreeComponent } from './components/family-tree/family-tree.component';
import { FAMILY_DATA, FamilyMember } from './data/mock-data';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FamilyTreeComponent, DatePipe],
  templateUrl: './app.component.html'
})
export class AppComponent {
  familyData = FAMILY_DATA;
  selectedPerson = signal<FamilyMember | null>(null);

  onMemberSelect(person: FamilyMember) {
    this.selectedPerson.set(person);
  }

  closeDetails() {
    this.selectedPerson.set(null);
  }
}

