    circleGroup.append('circle')
      .attr('r', 8)
      .attr('class', (d: any) => d.data.gender === 'male' ? 'fill-blue-500 stroke-white' : 'fill-pink-500 stroke-white')
      .attr('stroke-width', 2);

    // +/- Icon
    circleGroup.append('text')
      .attr('dy', 3)
      .attr('text-anchor', 'middle')
      .attr('class', 'text-[10px] fill-white font-bold select-none')
      .text((d: any) => d._children ? '+' : (d.children ? '-' : ''));

    // UPDATE nodes
    const nodeUpdate = node.merge(nodeEnter);

    nodeUpdate.transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${d.x},${d.y})`);

    // Update toggle text
    nodeUpdate.select('.toggle-btn text')
       .text((d: any) => d._children ? '+' : (d.children ? '-' : ''));

    // Hide toggle button if no children
    nodeUpdate.select('.toggle-btn')
       .attr('display', (d: any) => (d.children || d._children) ? 'block' : 'none');

    // EXIT nodes
    const nodeExit = node.exit().transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${source.x},${source.y})`)
      .remove();

    nodeExit.select('rect').attr('r', 1e-6);
    nodeExit.select('text').style('fill-opacity', 1e-6);

    // ------------------- LINKS -------------------
    this.updateLinks(source, this.links);

    // Store positions for next animation
    nodes.forEach((d: any) => {
      d.x0 = d.x;
      d.y0 = d.y;
    });
  }

  private updateLinks(source?: any, linksData?: any) {
    // If not provided (dragging), use cached links to avoid re-layout reset
    if (!linksData) {
        linksData = this.links;
    }

    // Function to generate path
    const diagonal = (s: any, d: any) => {
        // Vertical tree: x is horizontal position, y is depth
        return `M ${s.x} ${s.y + 45}
                C ${s.x} ${s.y + 45 + 50},
                  ${d.x} ${d.y - 45 - 50},
                  ${d.x} ${d.y - 45}`;
    };

    const link = this.g.selectAll('path.link')
      .data(linksData, (d: any) => d.target.id);

    // Enter
    const linkEnter = link.enter().insert('path', 'g')
      .attr('class', 'link')
      .attr('d', (d: any) => {
        const o = { x: source?.x0 || this.root.x0, y: source?.y0 || this.root.y0 };
        return diagonal(o, o); // Start from collapsed position
      });

    // Update (Merge)
    const linkUpdate = link.merge(linkEnter);

    if (source) {
       // If source is provided, we are animating (expand/collapse)
       linkUpdate.transition()
        .duration(this.duration)
        .attr('d', (d: any) => diagonal(d.source, d.target));
    } else {
       // If no source (dragging), update immediately without transition
       linkUpdate.attr('d', (d: any) => diagonal(d.source, d.target));
    }

    // Exit
    if (source) {
        link.exit().transition()
        .duration(this.duration)
        .attr('d', (d: any) => {
            const o = { x: source.x, y: source.y };
            return diagonal(o, o);
        })
        .remove();
    } else {
        link.exit().remove();
    }
  }

  // Toggle children on click
  private click(d: any) {
    if (d.children) {
      d._children = d.children;
      d.children = null;
    } else {
      d.children = d._children;
      d._children = null;
    }
    this.update(d);
  }
}

