}

import { Component, ElementRef, ViewChild, AfterViewInit, input, effect, OnDestroy, ViewEncapsulation, signal } from '@angular/core';
import { DatePipe } from '@angular/common';
import * as d3 from 'd3';
import { FamilyMember } from '../../data/mock-data';

// Extend D3 Node type for our custom properties
interface HierarchyNode extends d3.HierarchyNode<FamilyMember> {
  x0?: number;
  y0?: number;
  x?: number;
  y?: number;
  allChildNodes?: HierarchyNode[]; // Store all original children nodes
  collapsedSpouseIds?: Set<string>; // Track which spouse's children are hidden
}

@Component({
  selector: 'app-family-tree',
  standalone: true,
  imports: [DatePipe],
  templateUrl: './family-tree.component.html',
  styles: [`
    :host {
      display: block;
      width: 100%;
      height: 100%;
    }
  `],
  encapsulation: ViewEncapsulation.None
})
export class FamilyTreeComponent implements AfterViewInit, OnDestroy {
  rootData = input.required<FamilyMember>();

  // State for selected person details
  selectedPerson = signal<FamilyMember | null>(null);

  @ViewChild('chartContainer') private containerRef!: ElementRef<HTMLDivElement>;

  private svg: any;
  private g: any;
  private root: any; // HierarchyNode
  private treeLayout: any;
  private width = 0;
  private height = 0;
  private duration = 500;
  private i = 0; // id counter for nodes
  private links: any[] = []; // Store links for drag updates

  // Card configuration
  private rectW = 160;
  private rectH = 80;
  private cardGap = 20;

  constructor() {
    effect(() => {
      const data = this.rootData();
      if (this.svg && data) {
        this.initializeTree(data);
      }
    });
  }

  ngAfterViewInit() {
    setTimeout(() => {
      if (this.rootData()) {
        this.initializeTree(this.rootData());
      }
    }, 100);

    // Handle resize
    window.addEventListener('resize', this.handleResize);
  }

  ngOnDestroy() {
    window.removeEventListener('resize', this.handleResize);
  }

  closeDetails() {
    this.selectedPerson.set(null);
  }

  private handleResize = () => {
    if (this.rootData()) {
      this.initializeTree(this.rootData());
    }
  }

  private enrichData(node: FamilyMember, parents: FamilyMember[] = []) {
    // 1. Assign parents to current node
    if (parents.length > 0) {
      node.parents = parents;
    }

    // 2. Sort children by spouse index
    if (node.children && node.children.length > 0) {
        const parentIds = [node.id, ...(node.spouses?.map(s => s.id) || [])];
        node.children.sort((a, b) => {
            const indexA = parentIds.indexOf(a.otherParentId || '');
            const indexB = parentIds.indexOf(b.otherParentId || '');
            const effectiveA = indexA === -1 ? 0 : indexA;
            const effectiveB = indexB === -1 ? 0 : indexB;
            return effectiveA - effectiveB;
        });
    }

    // Prepare parents list
    let currentParents: FamilyMember[] = [node];

    // 3. Handle Spouses
    if (node.spouses && node.spouses.length > 0) {
      node.spouses.forEach(spouse => {
        spouse.spouses = [node];
        // Assign only children specific to this spouse (biological mother) for logic checks
        // Note: D3 still uses the main node's 'children' array for structure
        if (node.children) {
            spouse.children = node.children.filter(child => child.otherParentId === spouse.id);
        }
        currentParents.push(spouse);
      });
    }

    // 4. Process Children recursively
    if (node.children && node.children.length > 0) {
      node.children.forEach(child => {
        let childSpecificParents = currentParents;
        if (child.otherParentId) {
            const mainParent = node;
            const spouseParent = currentParents.find(p => p.id === child.otherParentId);
            if (spouseParent) {
                childSpecificParents = [mainParent, spouseParent];
            }
        }
        this.enrichData(child, childSpecificParents);
      });
    }
  }

  private initializeTree(data: FamilyMember) {
    if (!this.containerRef) return;

    this.enrichData(data);

    d3.select(this.containerRef.nativeElement).selectAll('*').remove();

    this.width = this.containerRef.nativeElement.clientWidth;
    this.height = this.containerRef.nativeElement.clientHeight;

    this.svg = d3.select(this.containerRef.nativeElement)
      .append('svg')
      .attr('width', '100%')
      .attr('height', '100%')
      .attr('viewBox', `0 0 ${this.width} ${this.height}`)
      .call(d3.zoom().scaleExtent([0.1, 3]).on('zoom', (event) => {
        this.g.attr('transform', event.transform);
      }))
      .on('dblclick.zoom', null);

    this.g = this.svg.append('g')
      .attr('transform', `translate(${this.width / 2}, 100)`);

    this.treeLayout = d3.tree().nodeSize([380, 220]); 

    // Convert data to hierarchy
    this.root = d3.hierarchy<FamilyMember>(data, (d) => d.children) as HierarchyNode;

    // Initialize Collapse State Tracking
    this.root.descendants().forEach((d: HierarchyNode) => {
        if (d.children) {
            d.allChildNodes = d.children as HierarchyNode[]; // Save strict reference to all children
            d.collapsedSpouseIds = new Set<string>();
        } else {
            d.allChildNodes = [];
            d.collapsedSpouseIds = new Set<string>();
        }
    });

    this.root.x0 = 0;
    this.root.y0 = 0;

    this.update(this.root);
  }

  private update(source: any) {
    const treeData = this.treeLayout(this.root);
    const nodes = treeData.descendants();
    this.links = treeData.links();

    // ------------------- NODES -------------------
    const node = this.g.selectAll('g.node')
      .data(nodes, (d: any) => d.id || (d.id = ++this.i));

    const component = this;

    // Enter new nodes
    const nodeEnter = node.enter().append('g')
      .attr('class', 'node')
      .attr('transform', (d: any) => `translate(${source.x0},${source.y0})`)
      .call(d3.drag()
        .on('start', function(event, d: any) { d3.select(this).raise(); }) 
        .on('drag', function(event, d: any) {
           d.x = event.x;
           d.y = event.y;
           d3.select(this).attr('transform', `translate(${d.x},${d.y})`);
           component.updateLinks();
        })
      );

    nodeEnter.on('click', (event: any) => {
      if (event.defaultPrevented) return;
      const target = d3.select(event.target);
      if (target.classed('person-card')) {
        const memberData = target.datum() as FamilyMember;
        if (memberData) {
            // Update local signal instead of emitting output
            component.selectedPerson.set(memberData);
        }
      }
    });

    // --- Render Cards & Spouses Loop ---
    nodeEnter.each(function(this: any, d: HierarchyNode) {
        const group = d3.select(this);
        const spouses = d.data.spouses || [];
        // The main node is index 0
        const totalMembers = [d.data, ...spouses];
        const count = totalMembers.length;

        const totalWidth = (count * component.rectW) + ((count - 1) * component.cardGap);
        const startX = -(totalWidth / 2);

        // Connector line between spouses
        if (count > 1) {
            group.append('line')
                .attr('x1', startX + component.rectW / 2)
                .attr('x2', startX + totalWidth - component.rectW / 2)
                .attr('y1', 0)
                .attr('y2', 0)
                .attr('stroke', '#94a3b8')
                .attr('stroke-width', 2);
        }

        // Render each member card
        totalMembers.forEach((member: FamilyMember, index: number) => {
            const cardX = startX + (index * (component.rectW + component.cardGap));
            const cardY = -component.rectH / 2;

            const cardGroup = group.append('g')
                .attr('transform', `translate(${cardX}, 0)`);

            // Card Rect
            cardGroup.append('rect')
                .attr('width', component.rectW)
                .attr('height', component.rectH)
                .attr('x', 0)
                .attr('y', cardY)
                .attr('rx', 8)
                .attr('ry', 8)
                .classed('person-card', true)
                .datum(member)
                .attr('class', () => {
                    const genderClass = member.gender === 'male' 
                    ? 'fill-blue-50 stroke-blue-200' 
                    : 'fill-pink-50 stroke-pink-200';
                    return `person-card ${genderClass} stroke-2 shadow-sm transition-colors hover:shadow-md cursor-pointer pointer-events-auto`;
                });

            // Name & Date
            cardGroup.append('text')
                .attr('x', component.rectW / 2)
                .attr('y', -5)
                .attr('text-anchor', 'middle')
                .text(member.name)
                .attr('class', 'text-sm font-bold fill-slate-800 pointer-events-none');

            cardGroup.append('text')
                .attr('x', component.rectW / 2)
                .attr('y', 15)
                .attr('text-anchor', 'middle')
                .text(member.birthDate ? new Date(member.birthDate).getFullYear() : '')
                .attr('class', 'text-xs fill-slate-500 pointer-events-none');

            // --- Toggle Button Logic Per Parent ---
            const hasChildren = d.allChildNodes && d.allChildNodes.some((childNode: any) => {
                const childData = childNode.data as FamilyMember;
                // If otherParentId matches this member
                if (childData.otherParentId === member.id) return true;
                // If no otherParentId and this is the main parent (index 0), they own these children
                if (!childData.otherParentId && index === 0) return true;
                return false;
            });

            if (hasChildren) {
                const isCollapsed = d.collapsedSpouseIds?.has(member.id || 'main');
                const trackId = member.id || 'main';

                const btnGroup = cardGroup.append('g')
                    .attr('class', 'toggle-btn cursor-pointer')
                    .attr('data-id', trackId) // Store ID for update phase
                    .attr('transform', `translate(${component.rectW / 2}, ${component.rectH / 2})`)
                    .on('click', (event: any) => {
                        event.stopPropagation();
                        component.toggleSpouseChildren(d, trackId);
                    });

                // Design: Dark Circle, White Text (Restored)
                btnGroup.append('circle')
                  .attr('r', 8)
                  .attr('class', 'fill-slate-600 stroke-white hover:fill-slate-700 transition-colors')
                  .attr('stroke-width', 2);

                // Symbol
                btnGroup.append('text')
                  .attr('dy', 3)
                  .attr('text-anchor', 'middle')
                  .attr('class', 'text-[10px] fill-white font-bold select-none')
                  .text(isCollapsed ? '+' : '-');
            }
        });
    });

    // Update Phase
    const nodeUpdate = node.merge(nodeEnter);

    nodeUpdate.transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${d.x},${d.y})`);

    // Explicitly update buttons text based on current state
    nodeUpdate.each(function(this: any, d: HierarchyNode) {
         const group = d3.select(this);
         group.selectAll('.toggle-btn').each(function(this: any) {
             const btn = d3.select(this);
             const spouseId = btn.attr('data-id');
             if (spouseId) {
                const isCollapsed = d.collapsedSpouseIds?.has(spouseId);
                btn.select('text').text(isCollapsed ? '+' : '-');
             }
         });
    });

    // Exit
    const nodeExit = node.exit().transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${source.x},${source.y})`)
      .remove();

    nodeExit.select('rect').attr('width', 0).attr('height', 0);
    nodeExit.style('opacity', 0);

    // ------------------- LINKS -------------------
    this.updateLinks(source, this.links);

    // Store positions
    nodes.forEach((d: any) => {
      d.x0 = d.x;
      d.y0 = d.y;
    });
  }

  private toggleSpouseChildren(d: HierarchyNode, spouseId: string) {
    if (!d.allChildNodes || !d.collapsedSpouseIds) return;

    if (d.collapsedSpouseIds.has(spouseId)) {
        d.collapsedSpouseIds.delete(spouseId);
    } else {
        d.collapsedSpouseIds.add(spouseId);
    }

    // Re-construct the visible 'children' array for D3
    if (d.allChildNodes.length > 0) {
        const visibleChildren = d.allChildNodes.filter((childNode: any) => {
            const childData = childNode.data as FamilyMember;
            // Determine who the visual parent is
            // If main parent (index 0) and no otherParentId, trackId is the main ID
            let parentId = childData.otherParentId;
            if (!parentId) {
                // If it belongs to the main father
                parentId = d.data.id || 'main'; 
            }

            // Check if this parentId is in the collapsed set
            // Note: If child belongs to Father (id '1'), check if '1' is in collapsedSpouseIds
            return !d.collapsedSpouseIds!.has(parentId);
        });

        d.children = visibleChildren.length > 0 ? visibleChildren : null;
    }

    this.update(d);
  }

  private updateLinks(source?: any, linksData?: any) {
    if (!linksData) linksData = this.links;

    const cardHalfH = this.rectH / 2;
    const verticalGap = 40;

    const getMemberOffset = (nodeData: FamilyMember, memberId?: string) => {
        if (!nodeData) return 0;
        const spouses = nodeData.spouses || [];
        const totalMembers = [nodeData, ...spouses];
        const count = totalMembers.length;
        const totalWidth = (count * this.rectW) + ((count - 1) * this.cardGap);
        const startX = -(totalWidth / 2);

        let index = 0;
        if (memberId) {
            const foundIndex = totalMembers.findIndex(m => m.id === memberId);
            if (foundIndex !== -1) index = foundIndex;
        }
        return startX + (index * (this.rectW + this.cardGap)) + (this.rectW / 2);
    };

    const diagonal = (s: any, d: any) => {
        const parentMemberId = d.data.otherParentId;
        const sOffset = getMemberOffset(s.data, parentMemberId);

        const tOffset = getMemberOffset(d.data, d.data.id);

        const sX = s.x + sOffset;
        const tX = d.x + tOffset;

        return `M ${sX} ${s.y + cardHalfH}
                V ${s.y + cardHalfH + 15}
                C ${sX} ${s.y + cardHalfH + verticalGap},
                  ${tX} ${d.y - cardHalfH - verticalGap},
                  ${tX} ${d.y - cardHalfH}`;
    };

    const link = this.g.selectAll('path.link')
      .data(linksData, (d: any) => d.target.id);

    const linkEnter = link.enter().insert('path', 'g')
      .attr('class', 'link')
      .attr('d', (d: any) => {
        const o = { x: source?.x0 || this.root.x0, y: source?.y0 || this.root.y0 };
        return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
      });

    const linkUpdate = link.merge(linkEnter);

    if (source) {
       linkUpdate.transition()
        .duration(this.duration)
        .attr('d', (d: any) => diagonal(d.source, d.target));
    } else {
       linkUpdate.attr('d', (d: any) => diagonal(d.source, d.target));
    }

    if (source) {
        link.exit().transition()
        .duration(this.duration)
        .attr('d', (d: any) => {
            const o = { x: source.x, y: source.y };
            return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
        })
        .remove();
    } else {
        link.exit().remove();
    }
  }
}

