    <content><![CDATA[import { Component, Input, OnInit, ElementRef, ViewChild, AfterViewInit } from '@angular/core';
import * as d3 from 'd3';
import { FamilyMember } from './family-member';

@Component({
  selector: 'app-family-tree',
  templateUrl: './family-tree.component.html',
  styleUrls: ['./family-tree.component.css']
})
export class FamilyTreeComponent implements OnInit, AfterViewInit {
  @Input() data: FamilyMember | null = null;
  @ViewChild('treeContainer') treeContainer: ElementRef | undefined;
  private svg: any;
  private treeLayout: any;
  private root: any;
  private links: any;
  private nodes: any;

  ngOnInit(): void {
    if (!this.data) {
      console.error('No data provided to FamilyTreeComponent');
    }
  }

  ngAfterViewInit(): void {
    if (this.data && this.treeContainer) {
      this.createTree(this.data);
    }
  }

  private createTree(data: FamilyMember): void {
    const margin = { top: 20, right: 90, bottom: 30, left: 90 };
    const width = 1200 - margin.left - margin.right;
    const height = 800 - margin.top - margin.bottom;

    this.svg = d3.select(this.treeContainer.nativeElement)
      .append('svg')
      .attr('width', width + margin.left + margin.right)
      .attr('height', height + margin.top + margin.bottom)
      .append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    this.initializeTree(data);
    this.update(data);
  }

  private initializeTree(data: FamilyMember): void {
    this.treeLayout = d3.tree().nodeSize([380, 220]);
    this.root = d3.hierarchy<FamilyMember>(data, (d) => d.children) as d3.HierarchyNode<FamilyMember>;

    this.root.x0 = 0;
    this.root.y0 = 0;
  }

  private update(data: FamilyMember): void {
    const treeData = this.treeLayout(this.root);
