// Helper function to create male-only tree
function filterMalesOnly(node: FamilyMember): FamilyMember | null {
  if (node.gender !== 'male') {
    return null;
  }

  // 1. Filter spouses (remove females)
  const filteredSpouses = node.spouses ? node.spouses.filter(s => s.gender === 'male') : [];

  // 2. Filter children recursively
  const filteredChildren = node.children 
      ? node.children
          .map(child => filterMalesOnly(child))
          .filter((child): child is FamilyMember => child !== null)
      : [];

  // 3. Re-assign children ownership
  // If the spouse a child belonged to is removed, assign child to the main father (remove otherParentId)
  // This ensures the visualization correctly attributes these children to the father in the absence of the mother,
  // enabling the collapse/expand toggle button.
  const currentSpouseIds = new Set(filteredSpouses.map(s => s.id));

  filteredChildren.forEach(child => {
      // If child has an otherParentId, but that parent is NOT in the current spouses list
      if (child.otherParentId && !currentSpouseIds.has(child.otherParentId)) {
          child.otherParentId = undefined; // Reset ownership to main parent
      }
  });

  const newNode: FamilyMember = {
    ...node,
    spouses: filteredSpouses,
    children: filteredChildren
  };

  return newNode;
}

export const MALE_ONLY_DATA = filterMalesOnly(FAMILY_DATA)!;

import { Component, ElementRef, ViewChild, AfterViewInit, input, effect, OnDestroy, ViewEncapsulation, signal } from '@angular/core';
import { DatePipe } from '@angular/common';
import * as d3 from 'd3';
import { FamilyMember } from '../../data/mock-data';

// Extend D3 Node type for our custom properties
interface HierarchyNode extends d3.HierarchyNode<FamilyMember> {
  x0?: number;
  y0?: number;
  x?: number;
  y?: number;
  allChildNodes?: HierarchyNode[];
  collapsedSpouseIds?: Set<string>;
}

@Component({
  selector: 'app-family-tree',
  imports: [DatePipe],
  templateUrl: './family-tree.component.html',
  styleUrl: './family-tree.component.css',
  encapsulation: ViewEncapsulation.None
})
export class FamilyTreeComponent implements AfterViewInit, OnDestroy {
  rootData = input.required<FamilyMember>();

  selectedPerson = signal<FamilyMember | null>(null);

  @ViewChild('chartContainer') private containerRef!: ElementRef<HTMLDivElement>;

  private svg: any;
  private g: any;
  private root: any; // HierarchyNode
  private treeLayout: any;
  private zoomBehavior: any; 
  private width = 0;
  private height = 0;
  private duration = 500;
  private i = 0;
  private links: any[] = []; 

  private rectW = 130; // Reduced width from 160
  private rectH = 80;
  private cardGap = 20;

  constructor() {
    effect(() => {
      const data = this.rootData();
      // Ensure view is initialized
      if (this.svg && data) {
        this.initializeTree(data);
      }
    });
  }

  ngAfterViewInit() {
    // Small timeout to allow DOM layout to settle and get correct dimensions
    setTimeout(() => {
      if (this.rootData()) {
        this.initializeTree(this.rootData());
      }
    }, 100);
    window.addEventListener('resize', this.handleResize);
  }

  ngOnDestroy() {
    window.removeEventListener('resize', this.handleResize);
  }

  closeDetails() {
    this.selectedPerson.set(null);
  }

  private handleResize = () => {
    if (this.rootData()) {
      this.initializeTree(this.rootData());
    }
  }

  private enrichData(node: FamilyMember, parents: FamilyMember[] = []) {
    if (parents.length > 0) node.parents = parents;

    if (node.children && node.children.length > 0) {
        const parentIds = [node.id, ...(node.spouses?.map(s => s.id) || [])];
        node.children.sort((a, b) => {
            const indexA = parentIds.indexOf(a.otherParentId || '');
            const indexB = parentIds.indexOf(b.otherParentId || '');
            const effectiveA = indexA === -1 ? 0 : indexA;
            const effectiveB = indexB === -1 ? 0 : indexB;
            return effectiveA - effectiveB;
        });
    }

    let currentParents: FamilyMember[] = [node];

    if (node.spouses && node.spouses.length > 0) {
      node.spouses.forEach(spouse => {
        spouse.spouses = [node];
        if (node.children) {
            spouse.children = node.children.filter(child => child.otherParentId === spouse.id);
        }
        currentParents.push(spouse);
      });
    }

    if (node.children && node.children.length > 0) {
      node.children.forEach(child => {
        let childSpecificParents = currentParents;
        if (child.otherParentId) {
            const mainParent = node;
            const spouseParent = currentParents.find(p => p.id === child.otherParentId);
            if (spouseParent) {
                childSpecificParents = [mainParent, spouseParent];
            }
        }
        this.enrichData(child, childSpecificParents);
      });
    }
  }

  private initializeTree(data: FamilyMember) {
    if (!this.containerRef) return;

    this.enrichData(data);

    // Clear existing
    d3.select(this.containerRef.nativeElement).selectAll('*').remove();

    this.width = this.containerRef.nativeElement.clientWidth;
    this.height = this.containerRef.nativeElement.clientHeight;

    // Guard against zero dimensions (if called before layout is ready)
    if (this.width === 0 || this.height === 0) return;

    this.zoomBehavior = d3.zoom()
      .scaleExtent([0.1, 3])
      .on('zoom', (event) => {
        this.g.attr('transform', event.transform);
      });

    this.svg = d3.select(this.containerRef.nativeElement)
      .append('svg')
      .attr('width', '100%')
      .attr('height', '100%')
      .attr('viewBox', `0 0 ${this.width} ${this.height}`)
      .call(this.zoomBehavior)
      .on('dblclick.zoom', null);

    this.g = this.svg.append('g');

    // Set initial position
    const initialTransform = d3.zoomIdentity.translate(this.width / 2, 50).scale(1);
    this.svg.call(this.zoomBehavior.transform, initialTransform);

    // DYNAMIC LAYOUT CONFIGURATION
    // 1. Reduced base nodeSize (Horizontal, Vertical) from [380, 220] to [200, 180]
    // 2. Added separation() to dynamically calculate width based on spouses
    this.treeLayout = d3.tree<FamilyMember>()
      .nodeSize([160, 180]) 
      .separation((a, b) => {
        const aSpouses = a.data.spouses?.length || 0;
        const bSpouses = b.data.spouses?.length || 0;

        // Calculate width factor: 1 for self + ~0.9 per spouse (visual width estimation)
        const aWidth = 1 + (aSpouses * 0.9);
        const bWidth = 1 + (bSpouses * 0.9);

        // Average width + gap
        const sep = (aWidth + bWidth) / 2 + 0.15;

        // Add extra space for cousins (different parents)
        return a.parent === b.parent ? sep : sep + 0.2;
      });

    this.root = d3.hierarchy<FamilyMember>(data, (d) => d.children) as HierarchyNode;

    // Initialize custom props
    this.root.descendants().forEach((d: HierarchyNode) => {
        if (d.children) {
            d.allChildNodes = d.children as HierarchyNode[];
            d.collapsedSpouseIds = new Set<string>();
        } else {
            d.allChildNodes = [];
            d.collapsedSpouseIds = new Set<string>();
        }
    });

    this.root.x0 = 0;
    this.root.y0 = 0;

    this.update(this.root);
  }

  private centerOnNode(d: HierarchyNode) {
    if (!this.svg || !this.zoomBehavior) return;

    const scale = 1.3;
    const sidebarWidth = 400; // Updated sidebar width

    const centerX = (this.width - sidebarWidth) / 2;
    const centerY = this.height / 2;

    const transform = d3.zoomIdentity
      .translate(centerX, centerY) 
      .scale(scale)
      .translate(-d.x!, -d.y!);

    this.svg.transition()
      .duration(750)
      .call(this.zoomBehavior.transform, transform);
  }

  private update(source: any) {
    const treeData = this.treeLayout(this.root);
    const nodes = treeData.descendants();
    this.links = treeData.links();

    // ------------------- NODES -------------------
    const node = this.g.selectAll('g.node')
      .data(nodes, (d: any) => d.id || (d.id = ++this.i));

    const component = this;

    const nodeEnter = node.enter().append('g')
      .attr('class', 'node')
      .attr('transform', (d: any) => `translate(${source.x0},${source.y0})`)
      .call(d3.drag()
        // Prevent drag behavior when interacting with the toggle button
        .filter((event: any) => !event.target.closest('.toggle-btn'))
        .on('start', function(event, d: any) { d3.select(this).raise(); }) 
        .on('drag', function(event, d: any) {
           d.x = event.x;
           d.y = event.y;
           d3.select(this).attr('transform', `translate(${d.x},${d.y})`);
           component.updateLinks();
        })
      );

    nodeEnter.on('click', (event: any, d: HierarchyNode) => {
      if (event.defaultPrevented) return;
      const target = d3.select(event.target);
      if (target.classed('person-card')) {
        const memberData = target.datum() as FamilyMember;
        if (memberData) {
            component.selectedPerson.set(memberData);
            component.centerOnNode(d);
        }
      }
    });

    nodeEnter.each(function(this: any, d: HierarchyNode) {
        const group = d3.select(this);
        const spouses = d.data.spouses || [];
        const totalMembers = [d.data, ...spouses];
        const count = totalMembers.length;

        const totalWidth = (count * component.rectW) + ((count - 1) * component.cardGap);
        const startX = -(totalWidth / 2);

        if (count > 1) {
            group.append('line')
                .attr('class', 'connector-line')
                .attr('x1', startX + component.rectW / 2)
                .attr('x2', startX + totalWidth - component.rectW / 2)
                .attr('y1', 0)
                .attr('y2', 0);
        }

        totalMembers.forEach((member: FamilyMember, index: number) => {
            const cardX = startX + (index * (component.rectW + component.cardGap));
            const cardY = -component.rectH / 2;

            const cardGroup = group.append('g')
                .attr('transform', `translate(${cardX}, 0)`);

            // Card Rect (Replaced Classes)
            cardGroup.append('rect')
                .attr('width', component.rectW)
                .attr('height', component.rectH)
                .attr('x', 0)
                .attr('y', cardY)
                .attr('rx', 8)
                .attr('ry', 8)
                .datum(member)
                .attr('class', () => {
                    const genderClass = member.gender === 'male' ? 'male' : 'female';
                    return `person-card ${genderClass}`;
                });

            // --- Image & Details ---
            const imgRadius = 22;
            const imgCx = component.rectW - 32;
            const imgCy = 0; 
            const uniqueClipId = `clip-${member.id || Math.random().toString(36).substr(2,9)}`;

            const defs = cardGroup.append('defs');
            defs.append('clipPath')
                .attr('id', uniqueClipId)
                .append('circle')
                .attr('cx', imgCx)
                .attr('cy', imgCy)
                .attr('r', imgRadius);

            cardGroup.append('image')
                .attr('href', member.photo)
                .attr('x', imgCx - imgRadius)
                .attr('y', imgCy - imgRadius)
                .attr('width', imgRadius * 2)
                .attr('height', imgRadius * 2)
                .attr('preserveAspectRatio', 'xMidYMid slice')
                .attr('clip-path', `url(#${uniqueClipId})`)
                .style('pointer-events', 'none');

            // Image Border
            cardGroup.append('circle')
                .attr('cx', imgCx)
                .attr('cy', imgCy)
                .attr('r', imgRadius)
                .attr('fill', 'none')
                .attr('stroke', member.gender === 'male' ? '#90caf9' : '#f48fb1')
                .attr('stroke-width', 2)
                .style('pointer-events', 'none');

            // Text
            const textX = component.rectW - 60; 

            cardGroup.append('text')
                .attr('x', textX)
                .attr('y', -5)
                .attr('text-anchor', 'start')
                .text(member.name)
                .attr('class', 'card-name');

            cardGroup.append('text')
                .attr('x', textX)
                .attr('y', 15)
                .attr('text-anchor', 'start')
                .text(member.birthDate ? new Date(member.birthDate).getFullYear() : '')
                .attr('class', 'card-date');

            // DNA Badge
            if (member.dna) {
               const dnaX = 20;
               const dnaY = component.rectH / 2 - 12;

               cardGroup.append('rect')
                 .attr('x', dnaX - 10)
                 .attr('y', dnaY - 8)
                 .attr('width', 26)
                 .attr('height', 14)
                 .attr('rx', 4)
                 .attr('class', 'badge-rect dna');

               cardGroup.append('text')
                 .attr('x', dnaX + 3)
                 .attr('y', dnaY + 2)
                 .attr('text-anchor', 'middle')
                 .text('DNA')
                 .attr('class', 'badge-text');
            }

            // TA Badge
            if (member.ta) {
               const taX = member.dna ? 50 : 20;
               const taY = component.rectH / 2 - 12;

               cardGroup.append('rect')
                 .attr('x', taX - 10)
                 .attr('y', taY - 8)
                 .attr('width', 26)
                 .attr('height', 14)
                 .attr('rx', 4)
                 .attr('class', 'badge-rect ta');

               cardGroup.append('text')
                 .attr('x', taX + 3)
                 .attr('y', taY + 2)
                 .attr('text-anchor', 'middle')
                 .text('TA')
                 .attr('class', 'badge-text');
            }

            // Toggle Button
            const hasChildren = d.allChildNodes && d.allChildNodes.some((childNode: any) => {
                const childData = childNode.data as FamilyMember;
                if (childData.otherParentId === member.id) return true;
                if (!childData.otherParentId && index === 0) return true;
                return false;
            });

            if (hasChildren) {
                const isCollapsed = d.collapsedSpouseIds?.has(member.id || 'main');
                const trackId = member.id || 'main';

                const btnGroup = cardGroup.append('g')
                    .attr('class', 'toggle-btn')
                    .attr('style', 'cursor: pointer')
                    .attr('data-id', trackId)
                    .attr('transform', `translate(${component.rectW / 2}, ${component.rectH / 2})`)
                    .on('click', (event: any) => {
                        event.stopPropagation();
                        component.toggleSpouseChildren(d, trackId);
                    });

                btnGroup.append('circle')
                  .attr('r', 8);

                btnGroup.append('text')
                  .attr('dy', 3)
                  .attr('text-anchor', 'middle')
                  .text(isCollapsed ? '+' : '-');
            }
        });
    });

    const nodeUpdate = node.merge(nodeEnter);

    nodeUpdate.transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${d.x},${d.y})`);

    // Update buttons
    nodeUpdate.each(function(this: any, d: HierarchyNode) {
         const group = d3.select(this);
         group.selectAll('.toggle-btn').each(function(this: any) {
             const btn = d3.select(this);
             const spouseId = btn.attr('data-id');
             if (spouseId) {
                const isCollapsed = d.collapsedSpouseIds?.has(spouseId);
                btn.select('text').text(isCollapsed ? '+' : '-');
             }
         });
    });

    const nodeExit = node.exit().transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${source.x},${source.y})`)
      .remove();

    nodeExit.select('rect').attr('width', 0).attr('height', 0);
    nodeExit.style('opacity', 0);

    // ------------------- LINKS -------------------
    this.updateLinks(source, this.links);

    nodes.forEach((d: any) => {
      d.x0 = d.x;
      d.y0 = d.y;
    });
  }

  private toggleSpouseChildren(d: HierarchyNode, spouseId: string) {
    if (!d.allChildNodes || !d.collapsedSpouseIds) return;

    if (d.collapsedSpouseIds.has(spouseId)) {
        d.collapsedSpouseIds.delete(spouseId);
    } else {
        d.collapsedSpouseIds.add(spouseId);
    }

    if (d.allChildNodes.length > 0) {
        const visibleChildren = d.allChildNodes.filter((childNode: any) => {
            const childData = childNode.data as FamilyMember;
            let parentId = childData.otherParentId;
            if (!parentId) {
                parentId = d.data.id || 'main'; 
            }
            return !d.collapsedSpouseIds!.has(parentId);
        });

        d.children = visibleChildren.length > 0 ? visibleChildren : null;
    }

    this.update(d);
  }

  private updateLinks(source?: any, linksData?: any) {
    if (!linksData) linksData = this.links;

    const cardHalfH = this.rectH / 2;
    const verticalGap = 40;

    const getMemberOffset = (nodeData: FamilyMember, memberId?: string) => {
        if (!nodeData) return 0;
        const spouses = nodeData.spouses || [];
        const totalMembers = [nodeData, ...spouses];
        const count = totalMembers.length;
        const totalWidth = (count * this.rectW) + ((count - 1) * this.cardGap);
        const startX = -(totalWidth / 2);

        let index = 0;
        if (memberId) {
            const foundIndex = totalMembers.findIndex(m => m.id === memberId);
            if (foundIndex !== -1) index = foundIndex;
        }
        return startX + (index * (this.rectW + this.cardGap)) + (this.rectW / 2);
    };

    const diagonal = (s: any, d: any) => {
        const parentMemberId = d.data.otherParentId;
        const sOffset = getMemberOffset(s.data, parentMemberId);
        const tOffset = getMemberOffset(d.data, d.data.id);

        const sX = s.x + sOffset;
        const tX = d.x + tOffset;

        return `M ${sX} ${s.y + cardHalfH}
                V ${s.y + cardHalfH + 15}
                C ${sX} ${s.y + cardHalfH + verticalGap},
                  ${tX} ${d.y - cardHalfH - verticalGap},
                  ${tX} ${d.y - cardHalfH}`;
    };

    const link = this.g.selectAll('path.link')
      .data(linksData, (d: any) => d.target.id);

    const linkEnter = link.enter().insert('path', 'g')
      .attr('class', 'link')
      .attr('d', (d: any) => {
        const o = { x: source?.x0 || this.root.x0, y: source?.y0 || this.root.y0 };
        return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
      });

    const linkUpdate = link.merge(linkEnter);

    if (source) {
       linkUpdate.transition()
        .duration(this.duration)
        .attr('d', (d: any) => diagonal(d.source, d.target));
    } else {
       linkUpdate.attr('d', (d: any) => diagonal(d.source, d.target));
    }

    if (source) {
        link.exit().transition()
        .duration(this.duration)
        .attr('d', (d: any) => {
            const o = { x: source.x, y: source.y };
            return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
        })
        .remove();
    } else {
        link.exit().remove();
    }
  }
}

import { Component, ElementRef, ViewChild, AfterViewInit, input, effect, OnDestroy, ViewEncapsulation, signal } from '@angular/core';
import { DatePipe } from '@angular/common';
import * as d3 from 'd3';
import { FamilyMember } from '../../data/mock-data';

// Extend D3 Node type for our custom properties
interface HierarchyNode extends d3.HierarchyNode<FamilyMember> {
  x0?: number;
  y0?: number;
  x?: number;
  y?: number;
  allChildNodes?: HierarchyNode[];
  collapsedSpouseIds?: Set<string>;
}

@Component({
  selector: 'app-family-tree',
  imports: [DatePipe],
  templateUrl: './family-tree.component.html',
  styleUrl: './family-tree.component.css',
  encapsulation: ViewEncapsulation.None
})
export class FamilyTreeComponent implements AfterViewInit, OnDestroy {
  rootData = input.required<FamilyMember>();

  selectedPerson = signal<FamilyMember | null>(null);

  @ViewChild('chartContainer') private containerRef!: ElementRef<HTMLDivElement>;

  private svg: any;
  private g: any;
  private root: any; // HierarchyNode
  private treeLayout: any;
  private zoomBehavior: any; 
  private width = 0;
  private height = 0;
  private duration = 500;
  private i = 0;
  private links: any[] = []; 

  private rectW = 130; // Reduced width
  private rectH = 80;
  private cardGap = 20;

  constructor() {
    effect(() => {
      const data = this.rootData();
      // Ensure view is initialized
      if (this.svg && data) {
        this.initializeTree(data);
      }
    });
  }

  ngAfterViewInit() {
    // Small timeout to allow DOM layout to settle and get correct dimensions
    setTimeout(() => {
      if (this.rootData()) {
        this.initializeTree(this.rootData());
      }
    }, 100);
    window.addEventListener('resize', this.handleResize);
  }

  ngOnDestroy() {
    window.removeEventListener('resize', this.handleResize);
  }

  closeDetails() {
    this.selectedPerson.set(null);
  }

  private handleResize = () => {
    if (this.rootData()) {
      this.initializeTree(this.rootData());
    }
  }

  private enrichData(node: FamilyMember, parents: FamilyMember[] = []) {
    if (parents.length > 0) node.parents = parents;

    if (node.children && node.children.length > 0) {
        const parentIds = [node.id, ...(node.spouses?.map(s => s.id) || [])];
        node.children.sort((a, b) => {
            const indexA = parentIds.indexOf(a.otherParentId || '');
            const indexB = parentIds.indexOf(b.otherParentId || '');
            const effectiveA = indexA === -1 ? 0 : indexA;
            const effectiveB = indexB === -1 ? 0 : indexB;
            return effectiveA - effectiveB;
        });
    }

    let currentParents: FamilyMember[] = [node];

    if (node.spouses && node.spouses.length > 0) {
      node.spouses.forEach(spouse => {
        spouse.spouses = [node];
        if (node.children) {
            spouse.children = node.children.filter(child => child.otherParentId === spouse.id);
        }
        currentParents.push(spouse);
      });
    }

    if (node.children && node.children.length > 0) {
      node.children.forEach(child => {
        let childSpecificParents = currentParents;
        if (child.otherParentId) {
            const mainParent = node;
            const spouseParent = currentParents.find(p => p.id === child.otherParentId);
            if (spouseParent) {
                childSpecificParents = [mainParent, spouseParent];
            }
        }
        this.enrichData(child, childSpecificParents);
      });
    }
  }

  private initializeTree(data: FamilyMember) {
    if (!this.containerRef) return;

    this.enrichData(data);

    // Clear existing
    d3.select(this.containerRef.nativeElement).selectAll('*').remove();

    this.width = this.containerRef.nativeElement.clientWidth;
    this.height = this.containerRef.nativeElement.clientHeight;

    // Guard against zero dimensions (if called before layout is ready)
    if (this.width === 0 || this.height === 0) return;

    this.zoomBehavior = d3.zoom()
      .scaleExtent([0.1, 3])
      .on('zoom', (event) => {
        this.g.attr('transform', event.transform);
      });

    this.svg = d3.select(this.containerRef.nativeElement)
      .append('svg')
      .attr('width', '100%')
      .attr('height', '100%')
      .attr('viewBox', `0 0 ${this.width} ${this.height}`)
      .call(this.zoomBehavior)
      .on('dblclick.zoom', null);

    this.g = this.svg.append('g');

    // Set initial position
    const initialTransform = d3.zoomIdentity.translate(this.width / 2, 50).scale(1);
    this.svg.call(this.zoomBehavior.transform, initialTransform);

    // DYNAMIC LAYOUT CONFIGURATION
    // 1. Reduced base nodeSize (Horizontal, Vertical) from [380, 220] to [200, 180]
    // 2. Added separation() to dynamically calculate width based on spouses
    this.treeLayout = d3.tree<FamilyMember>()
      .nodeSize([160, 180]) 
      .separation((a, b) => {
        const aSpouses = a.data.spouses?.length || 0;
        const bSpouses = b.data.spouses?.length || 0;

        // Calculate width factor: 1 for self + ~0.9 per spouse (visual width estimation)
        const aWidth = 1 + (aSpouses * 0.9);
        const bWidth = 1 + (bSpouses * 0.9);

        // Average width + gap
        const sep = (aWidth + bWidth) / 2 + 0.15;

        // Add extra space for cousins (different parents)
        return a.parent === b.parent ? sep : sep + 0.2;
      });

    this.root = d3.hierarchy<FamilyMember>(data, (d) => d.children) as HierarchyNode;

    // Initialize custom props
    this.root.descendants().forEach((d: HierarchyNode) => {
        if (d.children) {
            d.allChildNodes = d.children as HierarchyNode[];
            d.collapsedSpouseIds = new Set<string>();
        } else {
            d.allChildNodes = [];
            d.collapsedSpouseIds = new Set<string>();
        }
    });

    this.root.x0 = 0;
    this.root.y0 = 0;

    this.update(this.root);
  }

  private centerOnNode(d: HierarchyNode) {
    if (!this.svg || !this.zoomBehavior) return;

    const scale = 1.3;
    const sidebarWidth = 400; // Updated sidebar width

    const centerX = (this.width - sidebarWidth) / 2;
    const centerY = this.height / 2;

    const transform = d3.zoomIdentity
      .translate(centerX, centerY) 
      .scale(scale)
      .translate(-d.x!, -d.y!);

    this.svg.transition()
      .duration(750)
      .call(this.zoomBehavior.transform, transform);
  }

  private update(source: any) {
    const treeData = this.treeLayout(this.root);
    const nodes = treeData.descendants();
    this.links = treeData.links();

    // ------------------- NODES -------------------
    const node = this.g.selectAll('g.node')
      .data(nodes, (d: any) => d.id || (d.id = ++this.i));

    const component = this;

    const nodeEnter = node.enter().append('g')
      .attr('class', 'node')
      .attr('transform', (d: any) => `translate(${source.x0},${source.y0})`)
      .call(d3.drag()
        // Prevent drag behavior when interacting with the toggle button
        .filter((event: any) => !event.target.closest('.toggle-btn'))
        .on('start', function(event, d: any) { d3.select(this).raise(); }) 
        .on('drag', function(event, d: any) {
           d.x = event.x;
           d.y = event.y;
           d3.select(this).attr('transform', `translate(${d.x},${d.y})`);
           component.updateLinks();
        })
      );

    nodeEnter.on('click', (event: any, d: HierarchyNode) => {
      if (event.defaultPrevented) return;
      const target = d3.select(event.target);
      // Check if target is person-card OR inside the foreignObject text area
      if (target.classed('person-card') || target.closest('foreignObject').size() > 0) {
        const memberData = d.data as FamilyMember;
        if (memberData) {
            component.selectedPerson.set(memberData);
            component.centerOnNode(d);
        }
      }
    });

    nodeEnter.each(function(this: any, d: HierarchyNode) {
        const group = d3.select(this);
        const spouses = d.data.spouses || [];
        const totalMembers = [d.data, ...spouses];
        const count = totalMembers.length;

        const totalWidth = (count * component.rectW) + ((count - 1) * component.cardGap);
        const startX = -(totalWidth / 2);

        if (count > 1) {
            group.append('line')
                .attr('class', 'connector-line')
                .attr('x1', startX + component.rectW / 2)
                .attr('x2', startX + totalWidth - component.rectW / 2)
                .attr('y1', 0)
                .attr('y2', 0);
        }

        totalMembers.forEach((member: FamilyMember, index: number) => {
            const cardX = startX + (index * (component.rectW + component.cardGap));
            const cardY = -component.rectH / 2;

            const cardGroup = group.append('g')
                .attr('transform', `translate(${cardX}, 0)`);

            // Card Rect
            cardGroup.append('rect')
                .attr('width', component.rectW)
                .attr('height', component.rectH)
                .attr('x', 0)
                .attr('y', cardY)
                .attr('rx', 8)
                .attr('ry', 8)
                .datum(member)
                .attr('class', () => {
                    const genderClass = member.gender === 'male' ? 'male' : 'female';
                    return `person-card ${genderClass}`;
                });

            // --- Image ---
            const imgRadius = 22;
            const imgCx = component.rectW - 32;
            const imgCy = 0; 
            const uniqueClipId = `clip-${member.id || Math.random().toString(36).substr(2,9)}`;

            const defs = cardGroup.append('defs');
            defs.append('clipPath')
                .attr('id', uniqueClipId)
                .append('circle')
                .attr('cx', imgCx)
                .attr('cy', imgCy)
                .attr('r', imgRadius);

            cardGroup.append('image')
                .attr('href', member.photo)
                .attr('x', imgCx - imgRadius)
                .attr('y', imgCy - imgRadius)
                .attr('width', imgRadius * 2)
                .attr('height', imgRadius * 2)
                .attr('preserveAspectRatio', 'xMidYMid slice')
                .attr('clip-path', `url(#${uniqueClipId})`)
                .style('pointer-events', 'none');

            // Image Border
            cardGroup.append('circle')
                .attr('cx', imgCx)
                .attr('cy', imgCy)
                .attr('r', imgRadius)
                .attr('fill', 'none')
                .attr('stroke', member.gender === 'male' ? '#90caf9' : '#f48fb1')
                .attr('stroke-width', 2)
                .style('pointer-events', 'none');

            // --- Text with ForeignObject for Wrapping ---
            // Available width calculation: Card Width (130) - Image Area (~55px) - Left Padding (5px)
            const foWidth = component.rectW - 55;
            const foHeight = component.rectH - 10;
            const foX = 5; 
            const foY = -component.rectH / 2 + 5;

            const fo = cardGroup.append('foreignObject')
                .attr('x', foX)
                .attr('y', foY)
                .attr('width', foWidth)
                .attr('height', foHeight)
                .style('overflow', 'visible')
                .style('pointer-events', 'none'); // Allow clicks to pass to rect, or handle on group

            fo.append('xhtml:div')
                .style('width', '100%')
                .style('height', '100%')
                .style('display', 'flex')
                .style('flex-direction', 'column')
                .style('justify-content', 'center')
                .style('align-items', 'flex-end') // Align right towards image
                .style('text-align', 'right')
                .style('font-family', 'Roboto, sans-serif')
                .style('line-height', '1.2')
                .html(`
                    <div style="font-weight: 700; font-size: 13px; color: #374151; margin-bottom: 2px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;" title="${member.name}">
                        ${member.name}
                    </div>
                    <div style="font-size: 11px; color: #6b7280;">
                        ${member.birthDate ? new Date(member.birthDate).getFullYear() : ''}
                    </div>
                `);

            // DNA Badge
            if (member.dna) {
               const dnaX = 20;
               const dnaY = component.rectH / 2 - 12;

               cardGroup.append('rect')
                 .attr('x', dnaX - 10)
                 .attr('y', dnaY - 8)
                 .attr('width', 26)
                 .attr('height', 14)
                 .attr('rx', 4)
                 .attr('class', 'badge-rect dna');

               cardGroup.append('text')
                 .attr('x', dnaX + 3)
                 .attr('y', dnaY + 2)
                 .attr('text-anchor', 'middle')
                 .text('DNA')
                 .attr('class', 'badge-text');
            }

            // TA Badge
            if (member.ta) {
               const taX = member.dna ? 50 : 20;
               const taY = component.rectH / 2 - 12;

               cardGroup.append('rect')
                 .attr('x', taX - 10)
                 .attr('y', taY - 8)
                 .attr('width', 26)
                 .attr('height', 14)
                 .attr('rx', 4)
                 .attr('class', 'badge-rect ta');

               cardGroup.append('text')
                 .attr('x', taX + 3)
                 .attr('y', taY + 2)
                 .attr('text-anchor', 'middle')
                 .text('TA')
                 .attr('class', 'badge-text');
            }

            // Toggle Button
            const hasChildren = d.allChildNodes && d.allChildNodes.some((childNode: any) => {
                const childData = childNode.data as FamilyMember;
                if (childData.otherParentId === member.id) return true;
                if (!childData.otherParentId && index === 0) return true;
                return false;
            });

            if (hasChildren) {
                const isCollapsed = d.collapsedSpouseIds?.has(member.id || 'main');
                const trackId = member.id || 'main';

                const btnGroup = cardGroup.append('g')
                    .attr('class', 'toggle-btn')
                    .attr('style', 'cursor: pointer')
                    .attr('data-id', trackId)
                    .attr('transform', `translate(${component.rectW / 2}, ${component.rectH / 2})`)
                    .on('click', (event: any) => {
                        event.stopPropagation();
                        component.toggleSpouseChildren(d, trackId);
                    });

                btnGroup.append('circle')
                  .attr('r', 8);

                btnGroup.append('text')
                  .attr('dy', 3)
                  .attr('text-anchor', 'middle')
                  .text(isCollapsed ? '+' : '-');
            }
        });
    });

    const nodeUpdate = node.merge(nodeEnter);

    nodeUpdate.transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${d.x},${d.y})`);

    // Update buttons
    nodeUpdate.each(function(this: any, d: HierarchyNode) {
         const group = d3.select(this);
         group.selectAll('.toggle-btn').each(function(this: any) {
             const btn = d3.select(this);
             const spouseId = btn.attr('data-id');
             if (spouseId) {
                const isCollapsed = d.collapsedSpouseIds?.has(spouseId);
                btn.select('text').text(isCollapsed ? '+' : '-');
             }
         });
    });

    const nodeExit = node.exit().transition()
      .duration(this.duration)
      .attr('transform', (d: any) => `translate(${source.x},${source.y})`)
      .remove();

    nodeExit.select('rect').attr('width', 0).attr('height', 0);
    nodeExit.style('opacity', 0);

    // ------------------- LINKS -------------------
    this.updateLinks(source, this.links);

    nodes.forEach((d: any) => {
      d.x0 = d.x;
      d.y0 = d.y;
    });
  }

  private toggleSpouseChildren(d: HierarchyNode, spouseId: string) {
    if (!d.allChildNodes || !d.collapsedSpouseIds) return;

    if (d.collapsedSpouseIds.has(spouseId)) {
        d.collapsedSpouseIds.delete(spouseId);
    } else {
        d.collapsedSpouseIds.add(spouseId);
    }

    if (d.allChildNodes.length > 0) {
        const visibleChildren = d.allChildNodes.filter((childNode: any) => {
            const childData = childNode.data as FamilyMember;
            let parentId = childData.otherParentId;
            if (!parentId) {
                parentId = d.data.id || 'main'; 
            }
            return !d.collapsedSpouseIds!.has(parentId);
        });

        d.children = visibleChildren.length > 0 ? visibleChildren : null;
    }

    this.update(d);
  }

  private updateLinks(source?: any, linksData?: any) {
    if (!linksData) linksData = this.links;

    const cardHalfH = this.rectH / 2;
    const verticalGap = 40;

    const getMemberOffset = (nodeData: FamilyMember, memberId?: string) => {
        if (!nodeData) return 0;
        const spouses = nodeData.spouses || [];
        const totalMembers = [nodeData, ...spouses];
        const count = totalMembers.length;
        const totalWidth = (count * this.rectW) + ((count - 1) * this.cardGap);
        const startX = -(totalWidth / 2);

        let index = 0;
        if (memberId) {
            const foundIndex = totalMembers.findIndex(m => m.id === memberId);
            if (foundIndex !== -1) index = foundIndex;
        }
        return startX + (index * (this.rectW + this.cardGap)) + (this.rectW / 2);
    };

    const diagonal = (s: any, d: any) => {
        const parentMemberId = d.data.otherParentId;
        const sOffset = getMemberOffset(s.data, parentMemberId);
        const tOffset = getMemberOffset(d.data, d.data.id);

        const sX = s.x + sOffset;
        const tX = d.x + tOffset;

        return `M ${sX} ${s.y + cardHalfH}
                V ${s.y + cardHalfH + 15}
                C ${sX} ${s.y + cardHalfH + verticalGap},
                  ${tX} ${d.y - cardHalfH - verticalGap},
                  ${tX} ${d.y - cardHalfH}`;
    };

    const link = this.g.selectAll('path.link')
      .data(linksData, (d: any) => d.target.id);

    const linkEnter = link.enter().insert('path', 'g')
      .attr('class', 'link')
      .attr('d', (d: any) => {
        const o = { x: source?.x0 || this.root.x0, y: source?.y0 || this.root.y0 };
        return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
      });

    const linkUpdate = link.merge(linkEnter);

    if (source) {
       linkUpdate.transition()
        .duration(this.duration)
        .attr('d', (d: any) => diagonal(d.source, d.target));
    } else {
       linkUpdate.attr('d', (d: any) => diagonal(d.source, d.target));
    }

    if (source) {
        link.exit().transition()
        .duration(this.duration)
        .attr('d', (d: any) => {
            const o = { x: source.x, y: source.y };
            return `M ${o.x} ${o.y} C ${o.x} ${o.y}, ${o.x} ${o.y}, ${o.x} ${o.y}`;
        })
        .remove();
    } else {
        link.exit().remove();
    }
  }
}

